/* ── TIMELINE ── */
const milestones = [
  { year: "2015", title: "The Beginning",       desc: "Aurora Dining opens its doors in the heart of Manhattan." },
  { year: "2017", title: "First Michelin Star",  desc: "Recognized for culinary excellence by the Michelin Guide." },
  { year: "2019", title: "Second Michelin Star", desc: "Elevated to two-star status for exceptional cuisine." },
  { year: "2021", title: "Wine Spectator Award", desc: "Honored with the Grand Award for our wine program." },
  { year: "2023", title: "Third Michelin Star",  desc: "Achieved the prestigious three-star Michelin rating." },
  { year: "2025", title: "Global Expansion",     desc: "Aurora Tokyo and Aurora London debut to critical acclaim." },
];

function Timeline() {
  return (
    <section className="section-wrapper section-center" style={{ backgroundColor: "var(--color-bg)" }}>
      <div className="section-container">
        <AnimatedSection>
          <span className="section-label">Our Journey</span>
          <h2 className="section-heading" style={{ color: "#fff" }}>Milestones</h2>
        </AnimatedSection>
        <SectionDivider />
        <div className="timeline-container" style={{ marginTop: "80px" }}>
          {milestones.map((m, i) => (
            <AnimatedSection key={m.year} delay={i * 0.1}>
              <div className="timeline-item">
                {/* Left side */}
                {i % 2 === 0 ? (
                  <div className="timeline-content-left">
                    <span className="timeline-year">{m.year}</span>
                    <h3 className="timeline-title">{m.title}</h3>
                    <p className="timeline-desc">{m.desc}</p>
                  </div>
                ) : (
                  <div />
                )}
                {/* Center dot */}
                <div className="timeline-dot" />
                {/* Right side */}
                {i % 2 === 1 ? (
                  <div className="timeline-content-right">
                    <span className="timeline-year">{m.year}</span>
                    <h3 className="timeline-title">{m.title}</h3>
                    <p className="timeline-desc">{m.desc}</p>
                  </div>
                ) : (
                  <div />
                )}
              </div>
            </AnimatedSection>
          ))}
        </div>
      </div>
    </section>
  );
}

